// ================================================
// DATEN VORBEREITEN - FГњR AI AGENT
// ================================================
// Dieser Code bereitet die Daten fГјr den AI Agent vor
// Der Agent schreibt E-Mails und PDFs SELBST
// ================================================

const offers = $('Unversendete Angebote holen').all();
const leads = $('Lead-Daten holen').all();
const lineItems = $('Line Items holen').all();

const results = [];

for (let i = 0; i < offers.length; i++) {
  const offer = offers[i].json;
  const lead = leads[i].json;

  // Finde alle Line Items fГјr dieses Offer
  const offerLineItems = lineItems
    .filter(item => item.json.offer_id === offer.id)
    .map(item => ({
      position: item.json.position,
      beschreibung: item.json.beschreibung,
      raum: item.json.raum_name || 'Standard',
      leistung: item.json.leistung || 'Maler',
      menge: item.json.menge,
      einheit: item.json.einheit || 'mВІ',
      einzelpreis: parseFloat(item.json.einzelpreis || 0),
      gesamtpreis: parseFloat(item.json.gesamtpreis || 0)
    }))
    .sort((a, b) => a.position - b.position);

  // Berechne Preise
  const gesamtpreis_netto = parseFloat(offer.gesamtpreis_netto || 0);
  const gesamtpreis_brutto = parseFloat(offer.gesamtpreis_brutto || 0);
  const mwst = gesamtpreis_brutto - gesamtpreis_netto;

  // Formatiere Datum
  const heute = new Date().toLocaleDateString('de-DE', {
    day: '2-digit',
    month: 'long',
    year: 'numeric'
  });

  const gueltig_bis = offer.gueltig_bis 
    ? new Date(offer.gueltig_bis).toLocaleDateString('de-DE', {
        day: '2-digit',
        month: 'long',
        year: 'numeric'
      })
    : null;

  // Erstelle strukturierte Ausgabe FГњR DEN AGENT
  results.push({
    json: {
      // Lead Informationen
      lead_id: lead.id,
      vorname: lead.vorname || '',
      nachname: lead.nachname || '',
      email: lead.email,
      telefon: lead.telefon || '',
      strasse: lead.strasse || '',
      plz: lead.plz || '',
      ort: lead.ort || '',

      // Offer Informationen
      offer_id: offer.id,
      angebots_nummer: offer.angebots_nummer,

      // Preise (numerisch UND formatiert)
      gesamtpreis_netto: gesamtpreis_netto,
      gesamtpreis_netto_formatted: gesamtpreis_netto.toFixed(2).replace('.', ','),
      gesamtpreis_brutto: gesamtpreis_brutto,
      gesamtpreis_brutto_formatted: gesamtpreis_brutto.toFixed(2).replace('.', ','),
      mwst: mwst,
      mwst_formatted: mwst.toFixed(2).replace('.', ','),

      // Daten
      datum_heute: heute,
      gueltig_bis: gueltig_bis,
      gueltig_bis_iso: offer.gueltig_bis,

      // Line Items (Array)
      line_items: offerLineItems,
      line_items_count: offerLineItems.length,

      // Zusammenfassung fГјr schnellen Гњberblick
      raeume_liste: [...new Set(offerLineItems.map(item => item.raum))].join(', '),
      leistungen_liste: [...new Set(offerLineItems.map(item => item.leistung))].join(', '),

      // WhatsApp Nummer (HIER DEINE NUMMER EINTRAGEN!)
      whatsapp_nummer: '491234567890', // в†ђ Г„NDERE DIES!

      // Weitere Meta-Daten
      created_at: offer.created_at,
      updated_at: offer.updated_at
    }
  });
}

return results;

// HTML aus Claude-Response extrahieren
const response = $input.first().json;
let html = response.content[0].text;

// Falls in Code-Block, extrahieren
if (html.includes('```html')) {
  html = html.split('```html')[1].split('```')[0].trim();
} else if (html.includes('```')) {
  html = html.split('```')[1].split('```')[0].trim();
}

return {
  json: {
    html: html,
    offer_id: $('Daten vorbereiten').first().json.offer_id
  }
};

